class Solution {
public:
    bool fairDistribution(int cookies, int students, int studentCookies[])
    {
        sort(studentCookies, studentCookies + students);
        int diff = 0;
        for (int i = 0; i + 1 < students; i++)
        {
            diff = studentCookies[i + 1] - studentCookies[i];
            if (diff > 1)
                return false;
        }
        return true;
    }
};

class Main {
public:
    static void main()
    {
        Solution solution;
        int num_cookies, num_students;
        cin >> num_cookies >> num_students;
        int* student_cookies = new int[num_students];
        for (int i = 0; i < num_students; i++)
            cin >> student_cookies[i];
        cout << (solution.fairDistribution(num_cookies, num_students, student_cookies) ? "true" : "false") << endl;
        delete[] student_cookies;
    }
};
